-- ============================================================
-- leads.sql — Tabela de Leads + dados iniciais (100 leads SP)
-- Execute: mysql -u crmuser -p'CrmRD@2026' crm < leads.sql
-- ============================================================

CREATE TABLE IF NOT EXISTS `leads` (
  `id`             INT(11)       NOT NULL AUTO_INCREMENT,
  `empresa`        VARCHAR(200)  NOT NULL,
  `segmento`       VARCHAR(100)  DEFAULT NULL,
  `cidade`         VARCHAR(150)  DEFAULT NULL,
  `telefone`       VARCHAR(30)   DEFAULT NULL,
  `email`          VARCHAR(200)  DEFAULT NULL,
  `redes_sociais`  JSON          DEFAULT NULL COMMENT '{"instagram":"url","facebook":"url","tiktok":"url","youtube":"url","linkedin":"url"}',
  `website`        VARCHAR(500)  DEFAULT NULL,
  `observacoes`    TEXT          DEFAULT NULL,
  `status`         ENUM('novo','contatado','convertido','em_negociacao','descartado') NOT NULL DEFAULT 'novo',
  `cliente_id`     INT(11)       DEFAULT NULL  COMMENT 'FK para clientes quando convertido',
  `convertido_em`  TIMESTAMP     NULL DEFAULT NULL,
  `convertido_por` VARCHAR(120)  DEFAULT NULL,
  `contatado_em`   TIMESTAMP     NULL DEFAULT NULL,
  `contatado_por`  VARCHAR(120)  DEFAULT NULL,
  `criado_em`      TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `atualizado_em`  TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_status`   (`status`),
  KEY `idx_empresa`  (`empresa`),
  KEY `idx_segmento` (`segmento`),
  KEY `idx_cliente`  (`cliente_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

